package com.example.userapp.network;

import android.util.Log;

import java.security.KeyManagementException;
import java.security.NoSuchAlgorithmException;
import java.util.concurrent.TimeUnit;

import javax.net.ssl.TrustManager;
import javax.net.ssl.TrustManagerFactory;
import javax.net.ssl.X509TrustManager;

import okhttp3.CertificatePinner;
import okhttp3.ConnectionSpec;
import okhttp3.OkHttpClient;
import okhttp3.TlsVersion;
import okhttp3.logging.HttpLoggingInterceptor;

import java.security.KeyStore;
import java.util.Arrays;

/**
 * Factory that creates a securely configured OkHttpClient.
 * 
 * Security measures:
 * - Enforces TLS 1.2+ only (no cleartext, no SSLv3, no TLS 1.0/1.1)
 * - Certificate pinning for all API domains
 * - Uses system default trust managers (no custom trust-all managers)
 * - Strict connection specs (MODERN_TLS only)
 * - Reasonable timeouts
 */
public class SecureOkHttpClientFactory {

    private static final String TAG = "SecureOkHttpClient";

    private static final int CONNECT_TIMEOUT_SECONDS = 30;
    private static final int READ_TIMEOUT_SECONDS = 30;
    private static final int WRITE_TIMEOUT_SECONDS = 30;

    // Certificate pins for the API domains.
    // Replace these with actual SHA-256 hashes of your server's public key.
    // You can obtain them via:
    //   openssl s_client -servername api.example.com -connect api.example.com:443 | \
    //   openssl x509 -pubkey -noout | openssl pkey -pubin -outform der | \
    //   openssl dgst -sha256 -binary | openssl enc -base64
    private static final String PIN_PRIMARY = "sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=";
    private static final String PIN_BACKUP = "sha256/BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB=";

    private SecureOkHttpClientFactory() {
        // Prevent instantiation
    }

    /**
     * Creates a secure OkHttpClient instance.
     *
     * @param enableLogging whether to enable HTTP logging (should be false in production)
     * @return a configured OkHttpClient
     */
    public static OkHttpClient create(boolean enableLogging) {
        OkHttpClient.Builder builder = new OkHttpClient.Builder();

        // Timeouts
        builder.connectTimeout(CONNECT_TIMEOUT_SECONDS, TimeUnit.SECONDS);
        builder.readTimeout(READ_TIMEOUT_SECONDS, TimeUnit.SECONDS);
        builder.writeTimeout(WRITE_TIMEOUT_SECONDS, TimeUnit.SECONDS);

        // Enforce modern TLS only — no cleartext traffic
        ConnectionSpec modernTls = new ConnectionSpec.Builder(ConnectionSpec.MODERN_TLS)
                .tlsVersions(TlsVersion.TLS_1_2, TlsVersion.TLS_1_3)
                .build();
        builder.connectionSpecs(Arrays.asList(modernTls));

        // Certificate pinning for all API environments
        CertificatePinner certificatePinner = new CertificatePinner.Builder()
                .add("api.example.com", PIN_PRIMARY, PIN_BACKUP)
                .add("api-dev.example.com", PIN_PRIMARY, PIN_BACKUP)
                .add("api-staging.example.com", PIN_PRIMARY, PIN_BACKUP)
                .build();
        builder.certificatePinner(certificatePinner);

        // Configure TLS socket factory with system trust managers (no trust-all!)
        try {
            TrustManagerFactory trustManagerFactory = TrustManagerFactory.getInstance(
                    TrustManagerFactory.getDefaultAlgorithm());
            trustManagerFactory.init((KeyStore) null);
            TrustManager[] trustManagers = trustManagerFactory.getTrustManagers();

            if (trustManagers.length == 0 || !(trustManagers[0] instanceof X509TrustManager)) {
                throw new IllegalStateException("Unexpected default trust managers");
            }

            X509TrustManager x509TrustManager = (X509TrustManager) trustManagers[0];
            TlsSocketFactory tlsSocketFactory = new TlsSocketFactory(trustManagers);

            builder.sslSocketFactory(tlsSocketFactory, x509TrustManager);
        } catch (NoSuchAlgorithmException | KeyManagementException | java.security.KeyStoreException e) {
            Log.e(TAG, "Failed to configure TLS socket factory", e);
            throw new RuntimeException("Unable to create secure OkHttpClient", e);
        }

        // Logging — only in non-production builds
        if (enableLogging) {
            HttpLoggingInterceptor loggingInterceptor = new HttpLoggingInterceptor(
                    message -> Log.d(TAG, message));
            // Use HEADERS level to avoid logging sensitive body data even in debug
            loggingInterceptor.setLevel(HttpLoggingInterceptor.Level.HEADERS);
            builder.addInterceptor(loggingInterceptor);
        }

        // Add auth token interceptor
        builder.addInterceptor(new AuthInterceptor());

        return builder.build();
    }
}

