package com.example.userapp.network;

import java.io.IOException;

import okhttp3.Interceptor;
import okhttp3.Request;
import okhttp3.Response;

/**
 * Interceptor that adds authorization headers to every request.
 * In a real app, retrieve the token from secure storage (e.g., Android Keystore / EncryptedSharedPreferences).
 */
public class AuthInterceptor implements Interceptor {

    @Override
    public Response intercept(Chain chain) throws IOException {
        Request originalRequest = chain.request();

        String token = getAuthToken();
        if (token == null || token.isEmpty()) {
            return chain.proceed(originalRequest);
        }

        Request authenticatedRequest = originalRequest.newBuilder()
                .header("Authorization", "Bearer " + token)
                .header("Accept", "application/json")
                .build();

        return chain.proceed(authenticatedRequest);
    }

    /**
     * Retrieves the auth token from secure storage.
     * TODO: Replace with actual secure token retrieval (EncryptedSharedPreferences / Keystore).
     */
    private String getAuthToken() {
        // Placeholder — in production, retrieve from EncryptedSharedPreferences or similar
        return TokenStore.getInstance().getToken();
    }
}

