package com.example.userapp.network;

/**
 * Simple singleton token store.
 * In production, use EncryptedSharedPreferences or Android Keystore.
 */
public class TokenStore {

    private static volatile TokenStore instance;
    private String token;

    private TokenStore() {
    }

    public static TokenStore getInstance() {
        if (instance == null) {
            synchronized (TokenStore.class) {
                if (instance == null) {
                    instance = new TokenStore();
                }
            }
        }
        return instance;
    }

    public synchronized String getToken() {
        return token;
    }

    public synchronized void setToken(String token) {
        this.token = token;
    }

    public synchronized void clearToken() {
        this.token = null;
    }
}

