package com.example.userapp;

import android.app.Application;
import android.util.Log;

import com.example.userapp.network.ApiClient;

/**
 * Application class that initializes the API client on startup.
 */
public class UserApplication extends Application {

    private static final String TAG = "UserApplication";

    @Override
    public void onCreate() {
        super.onCreate();

        // Initialize the API client early to catch configuration errors
        try {
            ApiClient.getInstance();
            Log.i(TAG, "API client initialized for environment: " + BuildConfig.BASE_URL);
        } catch (SecurityException e) {
            Log.e(TAG, "FATAL: Insecure API configuration detected", e);
            throw e;
        }
    }
}

